const slugify = (value) => value
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/(^-|-$)/g, '');

const withArticleId = (article) => ({
  id: article.id || slugify(article.title),
  ...article,
});

const CATEGORIES = [...new Set(CONTENT_LIBRARY.map((article) => article.category))]
  .map((category) => ({
    id: category,
    label: category,
    icon: CATEGORY_META[category]?.icon || '📖',
    color: CATEGORY_META[category]?.color || '#5672ff',
  }));

// @desc    Get all content articles
// @route   GET /api/content
// @access  Public
const getContent = (req, res) => {
  const { category, featured } = req.query;
  let content = CONTENT_LIBRARY.map(withArticleId);

  if (category) {
    content = content.filter((c) => c.category === category);
  }

  if (featured === 'true') {
    content = content.filter((c) => c.featured);
  }

  // Return without full content for listing
  const listing = content.map(({ content: _, ...rest }) => rest);

  res.json({ success: true, count: listing.length, articles: listing, categories: CATEGORIES });
};

// @desc    Get single content article
// @route   GET /api/content/:id
// @access  Public
const getArticle = (req, res) => {
  const article = CONTENT_LIBRARY.map(withArticleId).find((a) => a.id === req.params.id);
  if (!article) {
    return res.status(404).json({ message: 'Article not found' });
  }
  res.json({ success: true, article, categories: CATEGORIES });
};

// @desc    Get categories
// @route   GET /api/content/categories
// @access  Public
const getCategories = (req, res) => {
  res.json({ success: true, categories: CATEGORIES });
};

module.exports = { getContent, getArticle, getCategories };
